// Config-driven MQTT normalizer.
// Default mappings cover common MQTT payloads. Override with EID_DEVICE_MAPPINGS_JSON.
// Mapping format:
// [{"topic":"tele/+/SENSOR","deviceId":"tasmota-${1}","deviceName":"Tasmota ${1}","deviceType":"tasmota","channels":[{"key":"el","path":"ENERGY.Total","scale":1}]}]

const topic = msg.topic || "";
const payload = msg.payload;
const allowRaw = (env.get("EID_DEVICE_ALLOWLIST") || "").trim();
const allowlist = allowRaw ? allowRaw.split(",").map(s => s.trim()).filter(Boolean) : [];
// Default 5000 points covers 1 Hz data buffered for over an hour, or 15 min intervals with margin.
const maxBufferPoints = parseInt(env.get("EID_MAX_BUFFER_POINTS") || "5000", 10);

const defaultMappings = [
    {
        topic: "tele/+/SENSOR",
        deviceId: "tasmota-${1}",
        deviceName: "Tasmota ${1}",
        deviceType: "tasmota",
        channels: [
            { key: "el", path: "ENERGY.Total", scale: 1 }
            // Optional examples the operator can enable in EID_DEVICE_MAPPINGS_JSON:
            // { key: "pwr", path: "ENERGY.Power", scale: 0.001 } // W -> kW
        ]
    },
    {
        topic: "shellies/+/relay/+/energy",
        deviceId: "shelly-${1}-r${2}",
        deviceName: "Shelly ${1} relay ${2}",
        deviceType: "shelly",
        channels: [
            { key: "el", path: "$payload", scale: 1 / 60000 } // watt-minutes -> kWh
        ]
    },
    {
        topic: "xky/+/tele/SENSOR",
        deviceId: "teleinfo-${1}",
        deviceName: "Teleinfo ${1}",
        deviceType: "teleinfo",
        channels: [
            { key: "el", path: "TIC.BASE", scale: 0.001, optional: true },
            { key: "el", path: "TIC.EAST", scale: 0.001, optional: true },
            { key: "el", paths: ["TIC.HCHC", "TIC.HCHP"], combine: "sum", scale: 0.001, optional: true },
            { key: "el", path: "BASE", scale: 0.001, optional: true },
            { key: "el", path: "EAST", scale: 0.001, optional: true },
            { key: "el", paths: ["HCHC", "HCHP"], combine: "sum", scale: 0.001, optional: true }
        ]
    }
];

function parseMappings() {
    const raw = (env.get("EID_DEVICE_MAPPINGS_JSON") || "").trim();
    if (!raw) return defaultMappings;
    try {
        const parsed = JSON.parse(raw);
        if (!Array.isArray(parsed)) throw new Error("mapping root must be an array");
        return parsed;
    } catch (e) {
        node.warn(`Invalid EID_DEVICE_MAPPINGS_JSON, using defaults: ${e.message}`);
        return defaultMappings;
    }
}

function topicMatch(pattern, actual) {
    const pp = String(pattern || "").split("/");
    const aa = String(actual || "").split("/");
    const captures = [];
    for (let i = 0, j = 0; i < pp.length; i++, j++) {
        const p = pp[i];
        if (p === "#") return { ok: true, captures };
        if (j >= aa.length) return { ok: false };
        if (p === "+") { captures.push(aa[j]); continue; }
        if (p !== aa[j]) return { ok: false };
    }
    return { ok: pp.length === aa.length, captures };
}

function applyTemplate(template, captures) {
    return String(template || "").replace(/\$\{(\d+)\}/g, (_, n) => captures[Number(n) - 1] || "");
}

function getPath(obj, path) {
    if (path === "$payload") return obj;
    return String(path || "").split(".").reduce((acc, part) => {
        if (acc === null || acc === undefined) return undefined;
        return acc[part];
    }, obj);
}

function numeric(v) {
    if (typeof v === "number") return isFinite(v) ? v : null;
    if (typeof v === "string" && v.trim() !== "") {
        const n = Number(v);
        return isFinite(n) ? n : null;
    }
    return null;
}

function extractChannel(ch, payload) {
    let value = null;
    if (Array.isArray(ch.paths)) {
        const vals = ch.paths.map(p => numeric(getPath(payload, p))).filter(v => v !== null);
        if (vals.length === 0) return null;
        value = ch.combine === "sum" ? vals.reduce((a, b) => a + b, 0) : vals[0];
    } else {
        value = numeric(getPath(payload, ch.path));
    }
    if (value === null) return null;
    value = value * Number(ch.scale === undefined ? 1 : ch.scale) + Number(ch.offset || 0);
    if (ch.min !== undefined && value < Number(ch.min)) return null;
    if (ch.max !== undefined && value > Number(ch.max)) return null;
    return value;
}

function rememberUnmapped(reason) {
    const unmapped = global.get("eid.unmappedTopics") || {};
    const entry = unmapped[topic] || { topic, count: 0, firstSeenAt: Date.now() };
    entry.count++;
    entry.lastSeenAt = Date.now();
    entry.reason = reason;
    entry.sampleType = typeof payload;
    if (payload && typeof payload === "object") entry.sampleKeys = Object.keys(payload).slice(0, 20);
    unmapped[topic] = entry;
    global.set("eid.unmappedTopics", unmapped);
    node.status({ fill: "grey", shape: "ring", text: `${topic}: ${reason}` });
}

function allow(id) { return allowlist.length === 0 || allowlist.includes(id); }

const mappings = parseMappings();
let match = null;
for (const mapping of mappings) {
    const m = topicMatch(mapping.topic, topic);
    if (m.ok) { match = { mapping, captures: m.captures }; break; }
}

if (!match) { rememberUnmapped("no mapping"); return null; }

const mapping = match.mapping;
const captures = match.captures;
const deviceId = applyTemplate(mapping.deviceId, captures);
const deviceName = applyTemplate(mapping.deviceName || mapping.deviceId, captures);
const deviceType = mapping.deviceType || "mqtt";
if (!deviceId) { rememberUnmapped("mapping produced empty deviceId"); return null; }
if (!allow(deviceId)) return null;

const readings = {};
for (const ch of (mapping.channels || [])) {
    const key = ch.key;
    if (!key) continue;
    const value = extractChannel(ch, payload);
    if (value === null) continue;
    readings[key] = value;
}

if (Object.keys(readings).length === 0) {
    rememberUnmapped(`${deviceId}: no mapped values`);
    return null;
}

const registry = global.get("eid.registry") || {};
let entry = registry[deviceId];
if (!entry) {
    const cc = (mapping.claimCode ? applyTemplate(mapping.claimCode, captures) : deviceId.replace(/[^A-Za-z0-9]/g, "").slice(-6)).toUpperCase();
    entry = {
        deviceId, deviceType, deviceName,
        claimCode: cc,
        helloAttempts: 0,
        helloLastTriedAt: 0,
        webhookUrl: null,
        headers: null,
        recordName: null,
        recordNumber: null,
        claimUrl: null,
        claimed: false,
        discoveredAt: Date.now()
    };
    registry[deviceId] = entry;
    global.set("eid.registry", registry);
    node.warn(`Discovered ${deviceId} (claimCode=${cc})`);
}
entry.lastSeenAt = Date.now();
entry.lastTopic = topic;
entry.lastReadings = readings;
global.set("eid.registry", registry);

const buffers = global.get("eid.buffers") || {};
buffers[deviceId] = buffers[deviceId] || [];
buffers[deviceId].push(Object.assign({ ts: Math.floor(Date.now() / 1000) }, readings));
if (buffers[deviceId].length > maxBufferPoints) buffers[deviceId].splice(0, buffers[deviceId].length - maxBufferPoints);
global.set("eid.buffers", buffers);

const summary = Object.keys(readings).map(k => `${k}=${Number(readings[k]).toFixed(3)}`).join(", ");
node.status({
    fill: entry.claimed ? "green" : "yellow",
    shape: "dot",
    text: `${deviceId} ${summary} (buf ${buffers[deviceId].length}, claimed=${entry.claimed})`
});

msg.deviceId = deviceId;
msg.readings = readings;
msg.mapping = { topic: mapping.topic, deviceType };
return msg;

const cooldown = parseInt(env.get("EID_HELLO_COOLDOWN_S") || "30", 10) * 1000;
const maxRetries = parseInt(env.get("EID_HELLO_MAX_RETRIES") || "20", 10);
const refreshEvery = parseInt(env.get("EID_CREDENTIAL_REFRESH_S") || "86400", 10) * 1000;
const now = Date.now();
const registry = global.get("eid.registry") || {};

function isForcedDeviceId(v) {
    return typeof v === "string" && v.trim().length > 0 && registry[v.trim()];
}

let target = null;
let reason = "";
const forcedId = isForcedDeviceId(msg.refreshDeviceId) ? msg.refreshDeviceId.trim()
    : isForcedDeviceId(msg.payload) ? msg.payload.trim()
    : null;

if (forcedId) {
    target = registry[forcedId];
    reason = "forced-refresh";
} else {
    for (const k of Object.keys(registry)) {
        const d = registry[k];
        if (!d || d.claimed) continue;
        if (d.helloAttempts >= maxRetries && (now - (d.helloLastTriedAt || 0)) < 3600000) continue;
        if ((now - (d.helloLastTriedAt || 0)) < cooldown) continue;
        target = d;
        reason = "claim";
        break;
    }
}

if (!target) {
    for (const k of Object.keys(registry)) {
        const d = registry[k];
        if (!d || !d.claimed) continue;
        if ((now - (d.helloLastTriedAt || 0)) < cooldown) continue;
        const lastRefresh = d.connectionRefreshedAt || d.claimedAt || d.discoveredAt || 0;
        if ((now - lastRefresh) < refreshEvery) continue;
        target = d;
        reason = "scheduled-refresh";
        break;
    }
}

if (!target) {
    node.status({ fill: "grey", shape: "ring", text: "queue idle" });
    return null;
}

target.helloAttempts = (target.helloAttempts || 0) + 1;
target.helloLastTriedAt = now;
global.set("eid.registry", registry);

msg.deviceId = target.deviceId;
msg.helloReason = reason;
msg.url = "https://hooks.energyid.eu/hello";
msg.method = "POST";
msg.headers = {
    "Content-Type": "application/json",
    "X-Provisioning-Key": env.get("ENERGYID_PROVISIONING_KEY"),
    "X-Provisioning-Secret": env.get("ENERGYID_PROVISIONING_SECRET")
};
msg.payload = {
    deviceId: target.deviceId,
    deviceName: target.deviceName,
    claimCode: target.claimCode
};
node.status({ fill: "blue", shape: "dot", text: `${reason} ${target.deviceId} #${target.helloAttempts}` });
return msg;

const status = msg.statusCode;
const body = msg.payload || {};
const registry = global.get("eid.registry") || {};
const dev = registry[msg.deviceId];
if (!dev) return null;

if (status !== 200 && status !== 201) {
    dev.connectionRefreshError = `HTTP ${status}`;
    global.set("eid.registry", registry);
    node.warn(`/hello ${msg.deviceId} -> HTTP ${status}: ${JSON.stringify(body).slice(0,200)}`);
    msg.outcome = `HTTP ${status}`;
    return msg;
}

if (body.webhookUrl && body.headers) {
    dev.webhookUrl     = body.webhookUrl;
    dev.headers        = body.headers;
    dev.recordName     = body.recordName;
    dev.recordNumber   = body.recordNumber;
    dev.uploadInterval = Number((body.webhookPolicy && body.webhookPolicy.uploadInterval) || 60);
    dev.claimed        = true;
    dev.claimedAt      = dev.claimedAt || Date.now();
    dev.connectionRefreshedAt = Date.now();
    dev.connectionRefreshError = null;
    dev.nextUploadAfter = 0;
    global.set("eid.registry", registry);
    const endpoint = String(body.webhookUrl).includes("servicebus") ? "servicebus" : "webhook";
    node.status({ fill: "green", shape: "dot", text: `${endpoint} ${msg.deviceId} ${dev.uploadInterval}s` });
    msg.outcome = `${msg.helloReason || "hello"} -> ${endpoint} ${dev.uploadInterval}s ${body.recordName}`;
    return msg;
}

if (body.claimUrl || body.claimCode) {
    dev.claimUrl  = body.claimUrl  || dev.claimUrl;
    dev.claimCode = body.claimCode || dev.claimCode;
    dev.claimed = false;
    dev.webhookUrl = null;
    dev.headers = null;
    dev.connectionRefreshedAt = null;
    global.set("eid.registry", registry);
    node.status({ fill: "yellow", shape: "ring", text: `pending ${msg.deviceId} (${dev.claimCode})` });
    msg.outcome = `pending claim ${dev.claimCode}`;
    return msg;
}

node.warn(`/hello ${msg.deviceId}: unexpected body ${JSON.stringify(body).slice(0,200)}`);
msg.outcome = "unexpected";
return msg;

const registry = global.get("eid.registry") || {};
const buffers  = global.get("eid.buffers")  || {};
const now = Date.now();
const maxBatchSize = parseInt(env.get("EID_MAX_BATCH_SIZE") || "1000", 10);

let sent = 0;
let waiting = 0;
for (const k of Object.keys(registry)) {
    const d = registry[k];
    if (!d || !d.claimed || !d.webhookUrl || !d.headers) continue;
    if (d.inflight) { waiting++; continue; }

    const buf = buffers[k] || [];
    if (buf.length === 0) continue;

    // Minimum send cadence is 60s: devices may publish 1s/10s samples, but we batch them to avoid per-sample HTTP requests.
    const intervalS = Math.max(60, Number(d.uploadInterval || 60));
    const nextDue = Number(d.nextUploadAfter || 0);
    if (now < nextDue) { waiting++; continue; }

    const batch = buf.splice(0, maxBatchSize);
    d.inflight = { batch, startedAt: now };
    d.nextUploadAfter = now + intervalS * 1000;

    node.send({
        deviceId: k,
        url: d.webhookUrl,
        method: "POST",
        headers: Object.assign({}, d.headers, { "Content-Type": "application/json" }),
        payload: batch
    });
    sent++;
}

global.set("eid.registry", registry);
global.set("eid.buffers", buffers);
node.status({
    fill: sent ? "blue" : "grey",
    shape: sent ? "dot" : "ring",
    text: sent ? `sent ${sent} batches` : (waiting ? `waiting ${waiting}` : "nothing to send")
});
return null;

const code = msg.statusCode;
const id   = msg.deviceId;
const registry = global.get("eid.registry") || {};
const buffers  = global.get("eid.buffers")  || {};
const maxBufferPoints = parseInt(env.get("EID_MAX_BUFFER_POINTS") || "5000", 10);
const d = registry[id];
const inflight = d && d.inflight;
const batch = inflight && Array.isArray(inflight.batch) ? inflight.batch : [];

msg.result = { deviceId: id, statusCode: code, body: msg.payload, sentCount: batch.length };

if (d) delete d.inflight;

if (code === 200 || code === 201 || code === 202 || code === 204) {
    if (d) {
        d.lastUploadAt = Date.now();
        d.failureCount = 0;
        d.lastUploadError = null;
    }
    global.set("eid.registry", registry);
    node.status({ fill: "green", shape: "dot", text: `OK ${id} (${code}, ${batch.length})` });
    return [msg, null];
}

if (batch.length) {
    buffers[id] = batch.concat(buffers[id] || []).slice(-maxBufferPoints);
}

if (d) {
    d.failureCount = (d.failureCount || 0) + 1;
    d.lastUploadError = `HTTP ${code}`;
}

const shouldReauth = code === 401 || code === 403 || code === 404;
if (shouldReauth && d) {
    d.claimed = false;
    d.webhookUrl = null;
    d.headers = null;
    d.helloAttempts = 0;
    d.helloLastTriedAt = 0;
    d.connectionRefreshedAt = null;
    d.nextUploadAfter = 0;
    global.set("eid.registry", registry);
    global.set("eid.buffers", buffers);
    node.warn(`${code} ${id} - re-auth queued, requeued ${batch.length}`);
    return [null, msg];
}

if (d) {
    const backoffS = code === 429 ? Math.max(300, Number(d.uploadInterval || 60)) : 60;
    d.nextUploadAfter = Date.now() + backoffS * 1000;
}
global.set("eid.registry", registry);
global.set("eid.buffers", buffers);
node.warn(`HTTP ${code} ${id}: ${JSON.stringify(msg.payload).slice(0,200)}; requeued ${batch.length}`);
return [null, msg];

const r = global.get("eid.registry") || {};
const b = global.get("eid.buffers")  || {};
const rows = Object.values(r).map(d => ({
    deviceId:   d.deviceId,
    type:       d.deviceType,
    claimed:    d.claimed,
    claimCode:  d.claimCode,
    recordName: d.recordName || "",
    recordNumber: d.recordNumber || "",
    endpoint:   d.webhookUrl && d.webhookUrl.includes("servicebus") ? "servicebus" : (d.webhookUrl ? "webhook" : ""),
    uploadInterval: d.uploadInterval || "",
    attempts:   d.helloAttempts,
    buffered:   (b[d.deviceId] || []).length,
    lastTopic:  d.lastTopic || "",
    lastReadings: d.lastReadings || {},
    claimUrl:   d.claimUrl || ""
}));
const claimed   = rows.filter(x => x.claimed);
const unclaimed = rows.filter(x => !x.claimed);
msg.payload = {
    total: rows.length,
    claimedCount: claimed.length,
    unclaimedCount: unclaimed.length,
    claimed,
    unclaimed,
    all: rows
};
return msg;

const r = global.get("eid.registry") || {};
const rows = Object.values(r).filter(d => !d.claimed);
const header = "deviceId,deviceType,claimCode,claimUrl";
const body = rows.map(d => `${d.deviceId},${d.deviceType},${d.claimCode},${d.claimUrl||""}`).join("\n");
msg.payload = header + "\n" + body + "\n";
msg.filename = "mqtt-bridge-unclaimed-" + new Date().toISOString().slice(0,10) + ".csv";
return msg;

global.set("eid.registry", {});
global.set("eid.buffers", {});
msg.payload = "registry + buffers cleared";
node.warn("MQTT bridge: registry and buffers wiped");
return msg;

const u = global.get("eid.unmappedTopics") || {};
const rows = Object.values(u).sort((a, b) => (b.lastSeenAt || 0) - (a.lastSeenAt || 0));
msg.payload = {
    total: rows.length,
    rows
};
return msg;

global.set("eid.unmappedTopics", {});
msg.payload = "unmapped topic list cleared";
return msg;
